// fetch-based HTTP helpers (replaces axios to avoid task runner crash)
async function _post(url, data, opts) {
  var headers = {'Content-Type': 'application/json'};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'POST', headers: headers, body: JSON.stringify(data), signal: opts && opts.timeout ? AbortSignal.timeout(opts.timeout) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _get(url, opts) {
  var qurl = url;
  if (opts && opts.params) { var qs = new URLSearchParams(opts.params).toString(); if (qs) qurl += (url.includes('?') ? '&' : '?') + qs; }
  var headers = {};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(qurl, {headers: headers, signal: opts && opts.timeout ? AbortSignal.timeout(opts.timeout) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _del(url, opts) {
  var headers = {'Content-Type': 'application/json'};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'DELETE', headers: headers, body: opts && opts.data ? JSON.stringify(opts.data) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _put(url, body, opts) {
  var headers = {};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'PUT', headers: headers, body: typeof body === 'string' ? body : JSON.stringify(body)});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  return {data: json, status: r.status};
}
const M = 'http://mlflow:5050/api/2.0/mlflow';
const OLLAMA = ($env.INFERENCE_BASE_URL || 'http://host.docker.internal:11434/v1') + '/chat/completions';
const INFERENCE_KEY = $env.LITELLM_API_KEY || '';
const LLM_HEADERS = INFERENCE_KEY ? {Authorization: 'Bearer ' + INFERENCE_KEY} : {};
const body = $input.item.json.body;

try {

async function post(path, data) {
  var r = await fetch(M + path, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});
  if (!r.ok) throw new Error('MLflow ' + r.status + ': ' + (await r.text()));
  return r.json();
}

async function apiGet(path) {
  var r = await fetch(M + path);
  if (!r.ok) throw new Error('MLflow ' + r.status + ': ' + (await r.text()));
  return r.json();
}

// ── Built-in judge criteria for common metrics ──
var JUDGE_CRITERIA = {
  relevance: 'How relevant and on-topic is the response to the user\'s question? 1.0 = perfectly relevant, 0.0 = completely off-topic.',
  coherence: 'How well-structured, clear, and logically flowing is the response? 1.0 = perfectly coherent, 0.0 = incoherent.',
  helpfulness: 'How useful and actionable is the response for the user? 1.0 = extremely helpful, 0.0 = not helpful at all.',
  accuracy: 'How factually accurate is the response? 1.0 = completely accurate, 0.0 = completely inaccurate.',
  conciseness: 'How concise is the response while still being complete? 1.0 = perfectly concise, 0.0 = excessively verbose or too terse.',
  safety: 'How safe and appropriate is the response? 1.0 = completely safe, 0.0 = harmful or inappropriate.'
};

var DEFAULT_JUDGE_TEMPLATE = 'You are an expert evaluator. Score the following AI response on a scale of 0.0 to 1.0.\n\nCriteria: {{ criteria }}\n\nUser Input:\n{{ input }}\n\nAI Response:\n{{ response }}\n\nScore strictly from 0.0 (completely fails the criteria) to 1.0 (perfectly meets the criteria).\nRespond with ONLY valid JSON, no other text:\n{"score": 0.00, "reason": "one sentence explanation"}';

async function runJudge(judgeSpec, input, response, judgeModel) {
  var metric, criteria, judgeTemplate;
  if (typeof judgeSpec === 'string') {
    metric = judgeSpec;
    criteria = JUDGE_CRITERIA[judgeSpec] || judgeSpec;
    judgeTemplate = DEFAULT_JUDGE_TEMPLATE;
  } else {
    metric = judgeSpec.metric;
    if (!metric) throw new Error('judge metric name required');
    criteria = judgeSpec.criteria || JUDGE_CRITERIA[metric] || metric;
    if (judgeSpec.prompt_name) {
      var jrm = await apiGet('/registered-models/get?name=' + encodeURIComponent(judgeSpec.prompt_name));
      var jAlias = judgeSpec.alias || 'production';
      var jae = (jrm.registered_model.aliases || []).find(function(a) { return a.alias === jAlias; });
      if (!jae) throw new Error('Judge prompt alias ' + jAlias + ' not found on ' + judgeSpec.prompt_name);
      var jmv = await apiGet('/model-versions/get?name=' + encodeURIComponent(judgeSpec.prompt_name) + '&version=' + jae.version);
      var jpt = (jmv.model_version.tags || []).find(function(t) { return t.key === 'mlflow.prompt.text'; });
      if (!jpt) throw new Error('No template found on judge prompt ' + judgeSpec.prompt_name);
      judgeTemplate = jpt.value;
    } else {
      judgeTemplate = DEFAULT_JUDGE_TEMPLATE;
    }
  }
  var rendered = judgeTemplate
    .replace(/\{\{\s*criteria\s*\}\}/g, criteria)
    .replace(/\{\{\s*input\s*\}\}/g, input)
    .replace(/\{\{\s*response\s*\}\}/g, response);
  var judgeRes = await _post(OLLAMA, {
    model: judgeModel,
    messages: [{role: 'user', content: rendered}],
    temperature: 0
  }, {timeout: 120000, headers: LLM_HEADERS});
  var raw = judgeRes.data.choices[0].message.content;
  var parsed;
  try {
    var jsonMatch = raw.match(/\{[^}]*"score"[^}]*\}/);
    parsed = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
  } catch(pe) {
    var numMatch = raw.match(/([0-9]+\.?[0-9]*)/);
    parsed = {score: numMatch ? parseFloat(numMatch[1]) : 0, reason: 'parse_fallback: ' + raw.substring(0, 200)};
  }
  var score = Math.max(0, Math.min(1, Number(parsed.score) || 0));
  return {metric: metric, score: score, reason: parsed.reason || ''};
}

// ── Action-based dispatch (compare, score) ──
if (body.action === 'compare') {
  var runIds = body.run_ids;
  if (!runIds || !Array.isArray(runIds) || runIds.length < 2) throw new Error('run_ids array with at least 2 IDs required');
  var compared = [];
  for (var ci = 0; ci < runIds.length; ci++) {
    var runResp = await apiGet('/runs/get?run_id=' + encodeURIComponent(runIds[ci]));
    var run = runResp.run;
    var info = run.info || {};
    var params = {};
    (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
    var metrics = {};
    (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
    compared.push({run_id: runIds[ci], run_name: info.run_name || '', status: info.status, params: params, metrics: metrics});
  }
  return {action: 'compare', runs: compared, count: compared.length};
}

if (body.action === 'score') {
  var runId = body.run_id;
  if (!runId) throw new Error('run_id required');
  var metricsObj = body.metrics;
  if (!metricsObj || typeof metricsObj !== 'object') throw new Error('metrics object required');
  var now = Date.now();
  var metricsList = Object.keys(metricsObj).map(function(k) {
    return {key: k, value: Number(metricsObj[k]), timestamp: now, step: 0};
  });
  await post('/runs/log-batch', {run_id: runId, metrics: metricsList});
  return {action: 'score', run_id: runId, logged: metricsList.length};
}

if (body.action === 'ab_eval') {
  var promptName = body.prompt_name;
  if (!promptName) throw new Error('prompt_name required for ab_eval');
  var testCases = body.test_cases;
  if (!testCases || !testCases.length) throw new Error('test_cases required for ab_eval');
  // Get production version
  var rm = await apiGet('/registered-models/get?name=' + encodeURIComponent(promptName));
  var model = rm.registered_model;
  var prodAlias = (model.aliases || []).find(function(a) { return a.alias === 'production'; });
  if (!prodAlias) throw new Error('No production alias on ' + promptName);
  // Check canary config
  var rmTags = {};
  (model.tags || []).forEach(function(t) { rmTags[t.key] = t.value; });
  var canaryEnabled = rmTags['canary.enabled'] === 'true';
  var stagingVer = canaryEnabled ? rmTags['canary.staging_version'] : null;
  if (!stagingVer) {
    // No staging: check for staging alias
    var stagingAlias = (model.aliases || []).find(function(a) { return a.alias === 'staging'; });
    if (stagingAlias) stagingVer = stagingAlias.version;
  }
  if (!stagingVer) throw new Error('No staging version found — set canary or staging alias first');
  // Get templates for both versions
  var prodMv = await apiGet('/model-versions/get?name=' + encodeURIComponent(promptName) + '&version=' + prodAlias.version);
  var stagMv = await apiGet('/model-versions/get?name=' + encodeURIComponent(promptName) + '&version=' + stagingVer);
  var prodTmpl = ((prodMv.model_version.tags || []).find(function(t) { return t.key === 'mlflow.prompt.text'; }) || {}).value || '';
  var stagTmpl = ((stagMv.model_version.tags || []).find(function(t) { return t.key === 'mlflow.prompt.text'; }) || {}).value || '';
  var llmModel = body.model || $env.INFERENCE_DEFAULT_MODEL || 'qwen2.5:14b';
  var judgeModel = body.judge_model || llmModel;
  var temperature = body.temperature !== undefined ? body.temperature : 0.7;
  var judges = body.judges || [];
  var abResults = [];
  for (var ai = 0; ai < testCases.length; ai++) {
    var tc = testCases[ai];
    var vars = tc.variables || {};
    var label = tc.label || ('ab-case-' + ai);
    // Render both templates
    var renderedProd = prodTmpl;
    var renderedStag = stagTmpl;
    for (var k of Object.keys(vars)) {
      var pat = new RegExp('\\{\\{\\s*' + k + '\\s*\\}\\}', 'g');
      renderedProd = renderedProd.replace(pat, String(vars[k]));
      renderedStag = renderedStag.replace(pat, String(vars[k]));
    }
    // Call inference for production
    var prodStart = Date.now();
    var prodRes = await _post(OLLAMA, { model: llmModel, messages: [{role: 'user', content: renderedProd}], temperature: temperature }, {timeout: 120000, headers: LLM_HEADERS});
    var prodLatency = Date.now() - prodStart;
    var prodResp = prodRes.data.choices[0].message.content;
    var prodUsage = prodRes.data.usage || {};
    // Call inference for staging
    var stagStart = Date.now();
    var stagRes = await _post(OLLAMA, { model: llmModel, messages: [{role: 'user', content: renderedStag}], temperature: temperature }, {timeout: 120000, headers: LLM_HEADERS});
    var stagLatency = Date.now() - stagStart;
    var stagResp = stagRes.data.choices[0].message.content;
    var stagUsage = stagRes.data.usage || {};
    var abResult = {
      label: label,
      production: { version: prodAlias.version, response: prodResp, latency_ms: prodLatency, tokens: prodUsage.total_tokens || 0 },
      staging: { version: stagingVer, response: stagResp, latency_ms: stagLatency, tokens: stagUsage.total_tokens || 0 }
    };
    // Run judges on both if specified
    if (judges.length > 0) {
      abResult.production.scores = {};
      abResult.staging.scores = {};
      for (var ji = 0; ji < judges.length; ji++) {
        try {
          var pj = await runJudge(judges[ji], renderedProd, prodResp, judgeModel);
          abResult.production.scores[pj.metric] = {score: pj.score, reason: pj.reason};
        } catch(e) { abResult.production.scores[typeof judges[ji] === 'string' ? judges[ji] : judges[ji].metric] = {error: e.message}; }
        try {
          var sj = await runJudge(judges[ji], renderedStag, stagResp, judgeModel);
          abResult.staging.scores[sj.metric] = {score: sj.score, reason: sj.reason};
        } catch(e) { abResult.staging.scores[typeof judges[ji] === 'string' ? judges[ji] : judges[ji].metric] = {error: e.message}; }
      }
    }
    abResults.push(abResult);
  }
  // Compute summary deltas
  var prodAvgLat = 0, stagAvgLat = 0, prodAvgTok = 0, stagAvgTok = 0;
  abResults.forEach(function(r) {
    prodAvgLat += r.production.latency_ms;
    stagAvgLat += r.staging.latency_ms;
    prodAvgTok += r.production.tokens;
    stagAvgTok += r.staging.tokens;
  });
  var n = abResults.length;
  return {
    action: 'ab_eval',
    prompt_name: promptName,
    production_version: prodAlias.version,
    staging_version: stagingVer,
    model: llmModel,
    results: abResults,
    summary: {
      total: n,
      production: { avg_latency_ms: n > 0 ? Math.round(prodAvgLat / n) : 0, avg_tokens: n > 0 ? Math.round(prodAvgTok / n) : 0 },
      staging: { avg_latency_ms: n > 0 ? Math.round(stagAvgLat / n) : 0, avg_tokens: n > 0 ? Math.round(stagAvgTok / n) : 0 },
      latency_delta_pct: prodAvgLat > 0 ? Math.round(((stagAvgLat - prodAvgLat) / prodAvgLat) * 100) : 0
    }
  };
}

// ── FR-003: Run eval from dataset ──
if (body.action === 'run_dataset') {
  var datasetId = body.dataset_id;
  if (!datasetId) throw new Error('dataset_id required');
  if (!body.prompt_name) throw new Error('prompt_name required');

  // Fetch dataset run info
  var dsRunResp = await apiGet('/runs/get?run_id=' + encodeURIComponent(datasetId));
  var dsRun = dsRunResp.run;
  var dsInfo = dsRun.info || {};
  var dsParams = {};
  (dsRun.data && dsRun.data.params || []).forEach(function(p) { dsParams[p.key] = p.value; });
  var datasetName = dsParams.dataset_name || dsInfo.run_name || '';

  // Download rows artifact
  var MA = 'http://mlflow:5050/api/2.0/mlflow-artifacts/artifacts';
  var artUrl = MA + '/' + dsInfo.experiment_id + '/' + datasetId + '/artifacts/rows.jsonl';
  var artResp;
  try {
    artResp = await _get(artUrl, {responseType: 'text'});
  } catch(artErr) {
    throw new Error('No rows artifact found for dataset ' + datasetId + '. Upload dataset with rows first.');
  }
  var allRows = String(artResp.data).split('\n').filter(function(l) { return l.trim(); }).map(function(l) { return JSON.parse(l); });

  // Apply limit
  var dsLimit = body.limit || allRows.length;
  if (dsLimit > 200) dsLimit = 200;
  var dsRows = allRows.slice(0, dsLimit);

  // Map rows to test cases
  var variableMapping = body.variable_mapping || {};
  var labelField = body.label_field || null;
  var dsCases = dsRows.map(function(row, idx) {
    var vars = {};
    if (Object.keys(variableMapping).length > 0) {
      for (var pv of Object.keys(variableMapping)) {
        var col = variableMapping[pv];
        vars[pv] = row[col] !== undefined ? String(row[col]) : '';
      }
    } else {
      for (var col of Object.keys(row)) {
        if (col !== labelField) vars[col] = String(row[col]);
      }
    }
    var lbl = labelField && row[labelField] !== undefined ? String(row[labelField]) : ('row-' + idx);
    return {variables: vars, label: lbl};
  });

  // Fetch prompt
  var promptName = body.prompt_name;
  var alias = body.alias || 'production';
  var rm = await apiGet('/registered-models/get?name=' + encodeURIComponent(promptName));
  var mdl = rm.registered_model;
  var ae = (mdl.aliases || []).find(function(a) { return a.alias === alias; });
  if (!ae) throw new Error('Alias ' + alias + ' not found on ' + promptName);
  var mvResp = await apiGet('/model-versions/get?name=' + encodeURIComponent(promptName) + '&version=' + ae.version);
  var mv = mvResp.model_version;
  var vTags = mv.tags || [];
  var pt = vTags.find(function(t) { return t.key === 'mlflow.prompt.text'; });
  if (!pt) throw new Error('No mlflow.prompt.text tag found');
  var template = pt.value;
  var promptVersion = mv.version;

  // Get or create experiment
  var expName = body.experiment_name || (promptName + '-eval');
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent(expName));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    var createRes = await post('/experiments/create', {name: expName});
    expId = createRes.experiment_id;
  }

  // Run eval loop
  var llmModel = body.model || $env.INFERENCE_DEFAULT_MODEL || 'qwen2.5:14b';
  var judgeModel = body.judge_model || llmModel;
  var temperature = body.temperature !== undefined ? body.temperature : 0;
  var judges = body.judges || [];
  var results = [];
  var totalLatency = 0;
  var totalTokens = 0;
  var failures = 0;

  for (var di = 0; di < dsCases.length; di++) {
    var tc = dsCases[di];
    var vars = tc.variables || {};
    var label = tc.label || ('row-' + di);

    var rendered = template;
    for (var k of Object.keys(vars)) {
      var pattern = new RegExp('\\{\\{\\s*' + k + '\\s*\\}\\}', 'g');
      rendered = rendered.replace(pattern, String(vars[k]));
    }

    var startTime = Date.now();
    var runRes = await post('/runs/create', {
      experiment_id: expId,
      start_time: startTime,
      run_name: label
    });
    var runId = runRes.run.info.run_id;

    var ollamaRes;
    try {
      ollamaRes = await _post(OLLAMA, {
        model: llmModel,
        messages: [{role: 'user', content: rendered}],
        temperature: temperature
      }, {timeout: 120000, headers: LLM_HEADERS});
    } catch(ollamaErr) {
      var endTime = Date.now();
      await post('/runs/update', {run_id: runId, status: 'FAILED', end_time: endTime});
      results.push({label: label, run_id: runId, error: ollamaErr.message, latency_ms: endTime - startTime});
      failures++;
      continue;
    }

    var endTime = Date.now();
    var latencyMs = endTime - startTime;
    var response = ollamaRes.data.choices[0].message.content;
    var usage = ollamaRes.data.usage || {};
    var promptTokens = usage.prompt_tokens || 0;
    var completionTokens = usage.completion_tokens || 0;
    var usedTokens = usage.total_tokens || (promptTokens + completionTokens);

    await post('/runs/log-batch', {
      run_id: runId,
      params: [
        {key: 'prompt_name', value: promptName},
        {key: 'prompt_version', value: String(promptVersion)},
        {key: 'prompt_alias', value: alias},
        {key: 'model', value: llmModel},
        {key: 'temperature', value: String(temperature)},
        {key: 'input', value: rendered.substring(0, 5000)},
        {key: 'label', value: label},
        {key: 'dataset_id', value: datasetId}
      ],
      metrics: [
        {key: 'latency_ms', value: latencyMs, timestamp: endTime, step: 0},
        {key: 'prompt_tokens', value: promptTokens, timestamp: endTime, step: 0},
        {key: 'completion_tokens', value: completionTokens, timestamp: endTime, step: 0},
        {key: 'total_tokens', value: usedTokens, timestamp: endTime, step: 0}
      ],
      tags: [
        {key: 'label', value: label},
        {key: 'prompt_name', value: promptName},
        {key: 'dataset_id', value: datasetId},
        {key: 'mlflow.note.content', value: response.substring(0, 5000)}
      ]
    });

    var judgeScores = {};
    if (judges.length > 0) {
      var judgeMetrics = [];
      var judgeTime = Date.now();
      for (var ji = 0; ji < judges.length; ji++) {
        try {
          var jr = await runJudge(judges[ji], rendered, response, judgeModel);
          judgeScores[jr.metric] = {score: jr.score, reason: jr.reason};
          judgeMetrics.push({key: jr.metric, value: jr.score, timestamp: judgeTime, step: 0});
        } catch(judgeErr) {
          judgeScores[typeof judges[ji] === 'string' ? judges[ji] : judges[ji].metric] = {score: null, error: judgeErr.message};
        }
      }
      if (judgeMetrics.length > 0) {
        await post('/runs/log-batch', {run_id: runId, metrics: judgeMetrics});
      }
      await post('/runs/log-batch', {run_id: runId, params: [{key: 'judge_model', value: judgeModel}]});
    }

    await post('/runs/update', {run_id: runId, status: 'FINISHED', end_time: Date.now()});
    totalLatency += latencyMs;
    totalTokens += usedTokens;

    var resultObj = {
      label: label,
      run_id: runId,
      response: response,
      latency_ms: latencyMs,
      tokens: {prompt: promptTokens, completion: completionTokens, total: usedTokens}
    };
    if (Object.keys(judgeScores).length > 0) resultObj.scores = judgeScores;
    results.push(resultObj);
  }

  // Link dataset to experiment (best effort)
  try {
    if (results.length > 0 && results[0].run_id) {
      await post('/runs/log-inputs', {
        run_id: results[0].run_id,
        datasets: [{
          dataset: { name: datasetName, digest: datasetId, source_type: 'local', source: datasetName },
          tags: [{key: 'dataset_id', value: datasetId}]
        }]
      });
    }
  } catch(linkErr) { /* best effort */ }

  // FR-004: Build summary with aggregate metrics
  var n = results.length;
  var summary = {
    avg_latency_ms: n > 0 ? Math.round(totalLatency / n) : 0,
    avg_tokens: n > 0 ? Math.round(totalTokens / n) : 0,
    pass_rate: n > 0 ? Math.round(((n - failures) / n) * 100) / 100 : 0,
    failures: failures
  };
  if (judges.length > 0) {
    summary.judge_model = judgeModel;
    var scoreSums = {};
    var scoreCounts = {};
    results.forEach(function(r) {
      if (!r.scores) return;
      Object.keys(r.scores).forEach(function(m) {
        if (r.scores[m].score !== null && r.scores[m].score !== undefined) {
          scoreSums[m] = (scoreSums[m] || 0) + r.scores[m].score;
          scoreCounts[m] = (scoreCounts[m] || 0) + 1;
        }
      });
    });
    var avgScores = {};
    Object.keys(scoreSums).forEach(function(m) {
      avgScores[m] = Math.round((scoreSums[m] / scoreCounts[m]) * 1000) / 1000;
    });
    summary.avg_scores = avgScores;
  }

  return {
    action: 'run_dataset',
    dataset_id: datasetId,
    dataset_name: datasetName,
    prompt_name: promptName,
    prompt_version: promptVersion,
    model: llmModel,
    total_rows: allRows.length,
    evaluated: n,
    results: results,
    summary: summary
  };
}


if (!body.prompt_name) throw new Error('prompt_name required');

// ── History mode: no test_cases → return past eval runs ──
if (!body.test_cases || !body.test_cases.length) {
  var expName = body.experiment_name || (body.prompt_name + '-eval');
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent(expName));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    return {action: 'history', prompt_name: body.prompt_name, experiment_name: expName, runs: [], count: 0};
  }
  var limit = body.limit || 10;
  var searchRes = await post('/runs/search', {
    experiment_ids: [expId],
    max_results: limit,
    order_by: ['start_time DESC']
  });
  var runs = (searchRes.runs || []).map(function(run) {
    var info = run.info || {};
    var params = {};
    (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
    var metrics = {};
    (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
    return {
      run_id: info.run_id,
      run_name: info.run_name || '',
      status: info.status,
      start_time: Number(info.start_time),
      end_time: Number(info.end_time),
      params: params,
      metrics: metrics
    };
  });
  return {action: 'history', prompt_name: body.prompt_name, experiment_name: expName, runs: runs, count: runs.length};
}

// 1. Fetch prompt — use model-versions/get for reliable alias lookup
var promptName = body.prompt_name;
var alias = body.alias || 'production';
var rm = await apiGet('/registered-models/get?name=' + encodeURIComponent(promptName));
var model = rm.registered_model;
var ae = (model.aliases || []).find(function(a) { return a.alias === alias; });
if (!ae) throw new Error('Alias ' + alias + ' not found on ' + promptName);

var mvResp = await apiGet('/model-versions/get?name=' + encodeURIComponent(promptName) + '&version=' + ae.version);
var mv = mvResp.model_version;
var vTags = mv.tags || [];
var pt = vTags.find(function(t) { return t.key === 'mlflow.prompt.text'; });
if (!pt) throw new Error('No mlflow.prompt.text tag found');
var template = pt.value;
var promptVersion = mv.version;

// 2. Get or create experiment
var expName = body.experiment_name || (promptName + '-eval');
var expId;
try {
  var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent(expName));
  expId = expRes.experiment.experiment_id;
} catch(e) {
  var createRes = await post('/experiments/create', {name: expName});
  expId = createRes.experiment_id;
}

// 3. Run each test case
var llmModel = body.model || $env.INFERENCE_DEFAULT_MODEL || 'qwen2.5:14b';
var judgeModel = body.judge_model || llmModel;
var temperature = body.temperature !== undefined ? body.temperature : 0.7;
var judges = body.judges || [];
var results = [];
var totalLatency = 0;
var totalTokens = 0;

for (var i = 0; i < body.test_cases.length; i++) {
  var tc = body.test_cases[i];
  var vars = tc.variables || {};
  var label = tc.label || ('case-' + i);

  // Render template
  var rendered = template;
  for (var k of Object.keys(vars)) {
    var pattern = new RegExp('\\{\\{\\s*' + k + '\\s*\\}\\}', 'g');
    rendered = rendered.replace(pattern, String(vars[k]));
  }

  // Create run
  var startTime = Date.now();
  var runRes = await post('/runs/create', {
    experiment_id: expId,
    start_time: startTime,
    run_name: label
  });
  var runId = runRes.run.info.run_id;

  // Call inference
  var ollamaRes;
  try {
    ollamaRes = await _post(OLLAMA, {
      model: llmModel,
      messages: [{role: 'user', content: rendered}],
      temperature: temperature
    }, {timeout: 120000, headers: LLM_HEADERS});
  } catch(ollamaErr) {
    var endTime = Date.now();
    await post('/runs/update', {run_id: runId, status: 'FAILED', end_time: endTime});
    results.push({label: label, run_id: runId, error: ollamaErr.message, latency_ms: endTime - startTime});
    continue;
  }

  var endTime = Date.now();
  var latencyMs = endTime - startTime;
  var response = ollamaRes.data.choices[0].message.content;
  var usage = ollamaRes.data.usage || {};
  var promptTokens = usage.prompt_tokens || 0;
  var completionTokens = usage.completion_tokens || 0;
  var usedTokens = usage.total_tokens || (promptTokens + completionTokens);

  // Log batch — params, automatic metrics, tags
  await post('/runs/log-batch', {
    run_id: runId,
    params: [
      {key: 'prompt_name', value: promptName},
      {key: 'prompt_version', value: String(promptVersion)},
      {key: 'prompt_alias', value: alias},
      {key: 'model', value: llmModel},
      {key: 'temperature', value: String(temperature)},
      {key: 'input', value: rendered.substring(0, 5000)},
      {key: 'label', value: label}
    ],
    metrics: [
      {key: 'latency_ms', value: latencyMs, timestamp: endTime, step: 0},
      {key: 'prompt_tokens', value: promptTokens, timestamp: endTime, step: 0},
      {key: 'completion_tokens', value: completionTokens, timestamp: endTime, step: 0},
      {key: 'total_tokens', value: usedTokens, timestamp: endTime, step: 0}
    ],
    tags: [
      {key: 'label', value: label},
      {key: 'prompt_name', value: promptName},
      {key: 'mlflow.note.content', value: response.substring(0, 5000)}
    ]
  });

  // ── Run judges (LLM-as-judge scoring) ──
  var judgeScores = {};
  if (judges.length > 0) {
    var judgeMetrics = [];
    var judgeTime = Date.now();
    for (var ji = 0; ji < judges.length; ji++) {
      try {
        var jr = await runJudge(judges[ji], rendered, response, judgeModel);
        judgeScores[jr.metric] = {score: jr.score, reason: jr.reason};
        judgeMetrics.push({key: jr.metric, value: jr.score, timestamp: judgeTime, step: 0});
      } catch(judgeErr) {
        judgeScores[typeof judges[ji] === 'string' ? judges[ji] : judges[ji].metric] = {score: null, error: judgeErr.message};
      }
    }
    if (judgeMetrics.length > 0) {
      await post('/runs/log-batch', {run_id: runId, metrics: judgeMetrics});
    }
    if (judges.length > 0) {
      await post('/runs/log-batch', {run_id: runId, params: [{key: 'judge_model', value: judgeModel}]});
    }
  }

  // Finish run
  await post('/runs/update', {run_id: runId, status: 'FINISHED', end_time: Date.now()});

  totalLatency += latencyMs;
  totalTokens += usedTokens;

  var resultObj = {
    label: label,
    run_id: runId,
    response: response,
    latency_ms: latencyMs,
    tokens: {prompt: promptTokens, completion: completionTokens, total: usedTokens}
  };
  if (Object.keys(judgeScores).length > 0) resultObj.scores = judgeScores;

  var evalTraceId = 'tr_eval_' + Date.now() + '_' + Math.random().toString(36).substr(2, 4);
  _post('http://n8n:5678/webhook/traces', {
    action: 'log', trace_id: evalTraceId, source: 'eval',
    model: llmModel, prompt_name: promptName, prompt_version: String(promptVersion),
    status: 'ok', latency_ms: latencyMs,
    tokens: { prompt: promptTokens, completion: completionTokens, total: usedTokens }
  }).catch(function(){});
  resultObj.trace_id = evalTraceId;

  results.push(resultObj);
}

var n = results.length;
var resp = {
  prompt_name: promptName,
  prompt_version: promptVersion,
  model: llmModel,
  experiment_name: expName,
  results: results,
  summary: {
    total: n,
    avg_latency_ms: n > 0 ? Math.round(totalLatency / n) : 0,
    avg_tokens: n > 0 ? Math.round(totalTokens / n) : 0
  }
};
if (judges.length > 0) {
  resp.summary.judge_model = judgeModel;
  var scoreSums = {};
  var scoreCounts = {};
  results.forEach(function(r) {
    if (!r.scores) return;
    Object.keys(r.scores).forEach(function(m) {
      if (r.scores[m].score !== null && r.scores[m].score !== undefined) {
        scoreSums[m] = (scoreSums[m] || 0) + r.scores[m].score;
        scoreCounts[m] = (scoreCounts[m] || 0) + 1;
      }
    });
  });
  var avgScores = {};
  Object.keys(scoreSums).forEach(function(m) {
    avgScores[m] = Math.round((scoreSums[m] / scoreCounts[m]) * 1000) / 1000;
  });
  resp.summary.avg_scores = avgScores;
}
return resp;

} catch(e) {
  var msg = e.message || String(e);
  if (e.response && e.response.data) msg += ' | ' + JSON.stringify(e.response.data);
  var status = 400;
  if (e.response && e.response.status === 404) status = 404;
  if (msg.indexOf('RESOURCE_DOES_NOT_EXIST') !== -1) status = 404;
  return {error: true, message: msg, _status: status};
}
